describe('pull partial sink', () => {
  it('should correctly pipe values through exactly 5 through streams without error', (done) => {
    // This test creates a partial pipeline with 5 through streams (triggering default case)
    // and verifies the output is correct. With mutation, the extra undefined in ref
    // causes pull.apply to receive undefined as an extra stream argument.
    // While undefined is silently ignored in the normal path, if the source passed
    // to the partial sink has .length === 1, pull enters partial sink branch again,
    // potentially causing incorrect behavior.

    const results: number[] = []
    const errors: any[] = []

    // Create 5 simple through streams that add 1 each
    const add1 = (read: Function) => (abort: any, cb: Function) => {
      read(abort, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, data + 1)
      })
    }

    // Create the partial pipeline with 5 throughs (triggers default case in switch)
    const pipeline = pull(add1, add1, add1, add1, add1)

    // Source that emits values 0, 1, 2
    const values = [0, 1, 2]
    let idx = 0
    const source = (abort: any, cb: Function) => {
      if (abort) return cb(abort)
      if (idx >= values.length) return cb(true)
      cb(null, values[idx++])
    }

    // Apply pipeline to source
    const piped = pipeline(source)

    // Collect results
    const collect = (read: Function) => {
      read(null, function next(end: any, data: any) {
        if (end === true) {
          try {
            expect(results).toEqual([5, 6, 7]) // 0+5, 1+5, 2+5
            done()
          } catch (e) {
            done(e)
          }
          return
        }
        if (end) return done(end)
        results.push(data)
        read(null, next)
      })
    }

    collect(piped)
