    // With mutation, ref has extra undefined, changing the captured length in the new partial sink.
    const composed = pipeline(add1)

    // composed should be a partial sink that, when given a real source, applies 6 add1s
    let idx = 0
    const source = (abort: any, cb: Function) => {
      if (abort) return cb(abort)
      if (idx >= 1) return cb(true)
      cb(null, idx++)
    }

    const piped = composed(source)

    piped(null, (end: any, data: any) => {
      if (end === true) {
        // We never got a value â€” this is a failure
        done(new Error('stream ended without producing a value'))
        return
      }
      if (end) {
        done(end instanceof Error ? end : new Error('stream error: ' + end))
        return
      }
      // 0 + 6 add1s = 6
      expect(data).toBe(6)
      done()
    })
  })
